"use client";

import { Home, Trophy, Plus } from "lucide-react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { setCurrentUser, clearCurrentUser } from "@/app/actions/session";

interface TopNavProps {
  currentUser: { id: string; name: string; displayName: string | null } | null;
  teamMembers: { id: string; name: string; displayName: string | null }[];
  onGiveKudos: () => void;
}

function AvatarPlaceholder({ name }: { name: string }) {
  const initials = name
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);
  return (
    <span
      className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-[#5b6880] text-sm font-medium text-white"
      aria-hidden
    >
      {initials}
    </span>
  );
}

export function TopNav({
  currentUser,
  teamMembers,
  onGiveKudos,
}: TopNavProps) {
  const pathname = usePathname();
  const isActive = (path: string) =>
    pathname === path || (path !== "/feed" && pathname.startsWith(path));

  return (
    <nav
      className="hidden sm:flex fixed top-0 left-0 right-0 bg-white border-b border-[#d8d9db] z-40"
      aria-label="Main navigation"
    >
      <div className="max-w-7xl mx-auto w-full px-6 py-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Link
              href="/feed"
              className="flex items-center gap-3 focus:outline-none focus:ring-2 focus:ring-[#5b6880] focus:ring-offset-2 rounded-lg"
            >
              <div className="w-10 h-10 bg-[#5b6880] rounded-lg flex items-center justify-center">
                <Trophy className="w-6 h-6 text-white" />
              </div>
              <span className="text-xl font-semibold text-[#212631]">Kudos</span>
            </Link>
          </div>

          <div className="flex items-center gap-2">
            <Link
              href="/feed"
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${
                isActive("/feed")
                  ? "text-[#5b6880] bg-[#d4d9e4]"
                  : "text-[#66686c] hover:text-[#5b6880] hover:bg-[#d8d9db]"
              }`}
            >
              <Home className="w-5 h-5" />
              <span className="font-medium">Feed</span>
            </Link>

            <Link
              href="/leaderboard"
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${
                isActive("/leaderboard")
                  ? "text-[#5b6880] bg-[#d4d9e4]"
                  : "text-[#66686c] hover:text-[#5b6880] hover:bg-[#d8d9db]"
              }`}
            >
              <Trophy className="w-5 h-5" />
              <span className="font-medium">Leaderboard</span>
            </Link>

            <button
              type="button"
              onClick={onGiveKudos}
              className="flex items-center gap-2 px-6 py-2 bg-[#357d1c] text-white rounded-lg hover:bg-[#49a628] transition-colors ml-2 font-medium focus:outline-none focus:ring-2 focus:ring-[#5b6880] focus:ring-offset-2"
            >
              <Plus className="w-5 h-5" />
              Give Kudos
            </button>

            {currentUser ? (
              <div className="flex items-center gap-2 ml-2 pl-2 border-l border-[#d8d9db]">
                <AvatarPlaceholder
                  name={currentUser.displayName ?? currentUser.name}
                />
                <span className="font-medium text-[#212631]">
                  {currentUser.displayName ?? currentUser.name}
                </span>
                <form action={clearCurrentUser} className="inline">
                  <button
                    type="submit"
                    className="text-sm text-[#5b6880] hover:underline focus:outline-none focus:ring-2 focus:ring-[#5b6880] focus:ring-offset-2 rounded"
                  >
                    Change
                  </button>
                </form>
              </div>
            ) : (
              <form
                action={setCurrentUser}
                className="flex items-center gap-2 ml-2"
              >
                <label
                  htmlFor="iam-select-top"
                  className="text-sm text-[#66686c] sr-only"
                >
                  I am
                </label>
                <select
                  id="iam-select-top"
                  name="teamMemberId"
                  required
                  className="rounded-lg border border-[#b0b2b6] px-3 py-2 text-sm text-[#212631] focus:outline-none focus:ring-2 focus:ring-[#5b6880] focus:border-transparent"
                  aria-label="Select your identity"
                >
                  <option value="">I am…</option>
                  {teamMembers.map((m) => (
                    <option key={m.id} value={m.id}>
                      {m.displayName ?? m.name}
                    </option>
                  ))}
                </select>
                <button
                  type="submit"
                  className="rounded-lg bg-[#357d1c] px-4 py-2 text-sm font-medium text-white hover:bg-[#49a628] focus:outline-none focus:ring-2 focus:ring-[#5b6880] focus:ring-offset-2"
                >
                  Continue
                </button>
              </form>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}
